 ```html
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu-style Desktop</title>
<style>
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    padding: 0;
    width: 100%;
    height: 100%;
    overflow: hidden;
    font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  }
  #desktop {
    position: relative;
    width: 100%;
    height: 100%;
    background: radial-gradient(circle at 20% 30%, #4b1d3f 0%, #2c0e24 40%, #150515 100%);
    color: #eee;
  }
  #topbar {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 28px;
    background: rgba(0, 0, 0, 0.35);
    backdrop-filter: blur(6px);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 14px;
    font-size: 13px;
    z-index: 1000;
  }
  #taskbar {
    position: absolute;
    bottom: 14px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    gap: 10px;
    padding: 8px 12px;
    background: rgba(30, 30, 30, 0.92);
    border: 1px solid #444;
    border-radius: 18px;
    box-shadow: 0 8px 24px rgba(0,0,0,0.55);
    z-index: 1000;
  }
  #taskbar button {
    width: 48px;
    height: 48px;
    border-radius: 12px;
    border: none;
    background: #2a2a2a;
    color: #fff;
    font-size: 22px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s;
  }
  #taskbar button:hover { background: #3d3d3d; }
  .window {
    position: absolute;
    width: 620px;
    height: 420px;
    min-width: 360px;
    min-height: 240px;
    background: #1e1e1e;
    border: 1px solid #444;
    border-radius: 10px;
    box-shadow: 0 12px 40px rgba(0,0,0,0.6);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    color: #eee;
  }
  .window.hidden { display: none; }
  .title-bar {
    height: 38px;
    background: linear-gradient(180deg, #333, #222);
    border-bottom: 1px solid #444;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    cursor: grab;
    user-select: none;
  }
  .win-title { font-weight: 600; font-size: 14px; }
  .win-close {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    border: none;
    background: #e81123;
    color: #fff;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 12px;
    line-height: 1;
  }
  .win-close:hover { background: #ff4d5e; }
  .window-content {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    padding: 10px;
  }
  .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 8px;
  }
  #files-up {
    padding: 4px 10px;
    background: #333;
    border: 1px solid #555;
    color: #eee;
    border-radius: 4px;
    cursor: pointer;
  }
  #files-up:disabled { opacity: 0.4; cursor: not-allowed; }
  #files-path {
    flex: 1;
    background: #111;
    border: 1px solid #333;
    padding: 4px 8px;
    border-radius: 4px;
    font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
    font-size: 13px;
    color: #9ef;
  }
  #files-list {
    flex: 1;
    overflow: auto;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(90px, 1fr));
    gap: 12px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    padding: 8px;
    border-radius: 6px;
    cursor: pointer;
    text-align: center;
    word-break: break-word;
    font-size: 12px;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item::before { font-size: 28px; line-height: 1; }
  .fs-item.folder::before { content: "📁"; }
  .fs-item.file::before { content: "📄"; }
  .notepad-toolbar {
    display: flex;
    align-items: center;
    gap: 4px;
    margin-bottom: 8px;
    border-bottom: 1px solid #444;
    padding-bottom: 6px;
  }
  #tabs {
    flex: 1;
    display: flex;
    gap: 4px;
    overflow-x: auto;
    align-items: center;
  }
  .tab {
    padding: 6px 10px;
    background: #2a2a2a;
    border: 1px solid #444;
    border-radius: 6px 6px 0 0;
    cursor: pointer;
    font-size: 13px;
    white-space: nowrap;
    display: flex;
    align-items: center;
    gap: 6px;
  }
  .tab.active {
    background: #3e3e3e;
    border-bottom-color: #3e3e3e;
  }
  .tab-close {
    width: 16px;
    height: 16px;
    border-radius: 50%;
    border: none;
    background: transparent;
    color: #aaa;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 11px;
    line-height: 1;
  }
  .tab-close:hover { background: #e81123; color: #fff; }
  #new-tab {
    padding: 6px 10px;
    background: #333;
    border: 1px solid #555;
    border-radius: 6px;
    color: #eee;
    cursor: pointer;
    font-size: 13px;
    white-space: nowrap;
  }
  #new-tab:hover { background: #444; }
  #editor {
    flex: 1;
    width: 100%;
    background: #111;
    color: #eee;
    border: 1px solid #333;
    border-radius: 6px;
    padding: 10px;
    font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;
    font-size: 14px;
    resize: none;
    outline: none;
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="topbar">
    <span>Activities</span>
    <span id="clock">00:00</span>
  </div>

  <div id="taskbar">
    <button id="open-files" title="Files">📁</button>
    <button id="open-notepad" title="Notepad">📝</button>
  </div>

  <div id="files-window" class="window hidden" style="top: 15%; left: 18%;">
    <div class="title-bar">
      <span class="win-title">Files</span>
      <button class="win-close">×</button>
    </div>
    <div class="window-content">
      <div class="files-toolbar">
        <button id="files-up">⬆ Up</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <div id="notepad-window" class="window hidden" style="top: 20%; left: 28%;">
    <div class="title-bar">
      <span class="win-title">Notepad</span>
      <button class="win-close">×</button>
    </div>
    <div class="window-content">
      <div class="notepad-toolbar">
        <div id="tabs">
          <button id="new-tab">+</button>
        </div>
      </div>
      <textarea id="editor" spellcheck="false"></textarea>
    </div>
  </div>
</div>

<script>
(function() {
  const $ = id => document.getElementById(id);
  let zIndex = 200;

  function bringFront(el) {
    el.style.zIndex = ++zIndex;
  }

  function showWindow(id) {
    const w = $(id);
    w.classList.remove('hidden');
    bringFront(w);
  }

  function hideWindow(w) {
    w.classList.add('hidden');
  }

  document.querySelectorAll('.win-close').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      hideWindow(btn.closest('.window'));
    });
  });

  $('open-files').addEventListener('click', () => showWindow('files-window'));
  $('open-notepad').addEventListener('click', () => showWindow('notepad-window'));

  function makeDraggable(win) {
    const tb = win.querySelector('.title-bar');
    let dragging = false;
    let offX = 0, offY = 0;

    tb.addEventListener('mousedown', (e) => {
      dragging = true;
      offX = e.clientX - win.offsetLeft;
      offY = e.clientY - win.offsetTop;
      bringFront(win);
    });

    document.addEventListener('mousemove', (e) => {
      if (!dragging) return;
      let x = e.clientX - offX;
      let y = e.clientY - offY;
      const maxX = window.innerWidth - win.offsetWidth;
      const maxY = window.innerHeight - win.offsetHeight;
      x = Math.max(0, Math.min(x, maxX));
      y = Math.max(0, Math.min(y, maxY));
      win.style.left = x + 'px';
      win.style.top = y + 'px';
    });

    document.addEventListener('mouseup', () => dragging = false);
    win.addEventListener('mousedown', () => bringFront(win));
  }

  makeDraggable($('files-window'));
  makeDraggable($('notepad-window'));

  const fsData = {
    type: 'dir',
    children: {
      bin: {
        type: 'dir',
        children: {
          bash: { type: 'file' },
          ls: { type: 'file' },
          node: { type: 'file' }
        }
      },
      etc: {
        type: 'dir',
        children: {
          hosts: { type: 'file' },
          'os-release': { type: 'file' },
          passwd: { type: 'file' }
        }
      },
      home: {
        type: 'dir',
        children: {
          user: {
            type: 'dir',
            children: {
              Documents: {
                type: 'dir',
                children: {
                  'notes.txt': { type: 'file' },
                  'resume.pdf': { type: 'file' },
                  project: {
                    type: 'dir',
                    children: {
                      'main.js': { type: 'file' },
                      'README.md': { type: 'file' }
                    }
                  }
                }
              },
              Downloads: {
                type: 'dir',
                children: {
                  'ubuntu.iso': { type: 'file' },
                  'archive.zip': { type: 'file' }
                }
              },
              Pictures: {
                type: 'dir',
                children: {
                  'wallpaper.png': { type: 'file' },
                  'cat.jpg': { type: 'file' },
                  vacation: {
                    type: 'dir',
                    children: {
                      'beach.jpg': { type: 'file' }
                    }
                  }
                }
              },
              'hello.txt': { type: 'file' }
            }
          }
        }
      },
      usr: {
        type: 'dir',
        children: {
          bin: { type: 'dir', children: {} },
          share: {
            type: 'dir',
            children: {
              themes: { type: 'dir', children: {} }
            }
          }
        }
      },
      var: {
        type: 'dir',
        children: {
          log: {
            type: 'dir',
            children: {
              syslog: { type: 'file' }
            }
          },
          tmp: { type: 'dir', children: {} }
        }
      }
    }
  };

  let currentPath = [];

  function getNode(pathArr) {
    let node = fsData;
    for (const name of pathArr) {
      node = node.children[name];
      if (!node) return null;
    }
    return node;
  }

  function renderFiles() {
    const node = getNode(currentPath);
    $('files-path').textContent = '/' + currentPath.join('/');
    $('files-up').disabled = currentPath.length === 0;

    const list = $('files-list');
    list.innerHTML = '';
    if (!node || !node.children) return;

    Object.keys(node.children).sort().forEach(name => {
      const entry = node.children[name];
      const el = document.createElement('div');
      el.className = 'fs-item ' + (entry.type === 'dir' ? 'folder' : 'file');
      el.textContent = name;
      if (entry.type === 'dir') {
        el.addEventListener('dblclick', () => {
          currentPath.push(name);
          renderFiles();
        });
      }
      list.appendChild(el);
    });
  }

  $('files-up').addEventListener('click', () => {
    if (currentPath.length) {
      currentPath.pop();
      renderFiles();
    }
  });

  renderFiles();

  const STORAGE_TABS = 'notepad-tabs';
  const STORAGE_ACTIVE = 'notepad-active';
  let tabs = [];
  let activeTabId = null;

  function generateId() {
    return 'tab_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2);
  }

  function saveTabs() {
    try {
      localStorage.setItem(STORAGE_TABS, JSON.stringify(tabs));
      localStorage.setItem(STORAGE_ACTIVE, activeTabId || '');
    } catch (e) {}
  }

  function loadTabs() {
    try {
      const raw = localStorage.getItem(STORAGE_TABS);
      if (raw) {
        const parsed = JSON.parse(raw);
        if (Array.isArray(parsed) && parsed.length) {
          tabs = parsed;
          activeTabId = localStorage.getItem(STORAGE_ACTIVE) || tabs[0].id;
          return;
        }
      }
    } catch (e) {}
    tabs = [{ id: generateId(), title: 'Untitled 1', content: '' }];
    activeTabId = tabs[0].id;
  }

  function nextUntitledNumber() {
    const nums = tabs.map(t => {
      const m = t.title.match(/^Untitled (\d+)$/);
      return m ? parseInt(m[1], 10) : 0;
    });
    return (nums.length ? Math.max(...nums) : 0) + 1;
  }

  function deriveTitle(content) {
    const line = content.split('\n').find(l => l.trim()) || '';
    return line.trim().slice(0, 25) || ('Untitled ' + nextUntitledNumber());
  }

  function createTab() {
    const id = generateId();
    tabs.push({ id, title: 'Untitled ' + nextUntitledNumber(), content: '' });
    setActiveTab(id);
    saveTabs();
  }

  function removeTab(id, event) {
    if (event) event.stopPropagation();
    if (tabs.length <= 1) {
      const t = tabs[0];
      t.content = '';
      t.title = 'Untitled 1';
      setActiveTab(t.id);
      saveTabs();
      return;
    }
    tabs = tabs.filter(t => t.id !== id);
    if (activeTabId === id) {
      activeTabId = tabs[0].id;
    }
    setActiveTab(activeTabId);
    saveTabs();
  }

  function setActiveTab(id) {
    activeTabId = id;
    renderTabs();
    const tab = tabs.find(t => t.id === id);
    $('editor').value = tab ? tab.content : '';
  }

  function renderTabs() {
    const container = $('tabs');
    const newBtn = $('new-tab');
    container.querySelectorAll('.tab').forEach(el => el.remove());
    tabs.forEach(tab => {
      const el = document.createElement('div');
      el.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
      el.textContent = tab.title;
      const close = document.createElement('button');
      close.className = 'tab-close';
      close.textContent = '×';
      close.addEventListener('click', (e) => removeTab(tab.id, e));
      el.appendChild(close);
      el.addEventListener('click', () => setActiveTab(tab.id));
      container.insertBefore(el, newBtn);
    });
  }

  $('new-tab').addEventListener('click', createTab);

  $('editor').addEventListener('input', () => {
    const tab = tabs.find(t => t.id === activeTabId);
    if (!tab) return;
    tab.content = $('editor').value;
    tab.title = deriveTitle(tab.content);
    renderTabs();
    saveTabs();
  });

  loadTabs();
  setActiveTab(activeTabId);

  function updateClock() {
    const now = new Date();
    $('clock').textContent = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }
  updateClock();
  setInterval(updateClock, 1000);
})();
</script>
</body>
</html>
